import { ref } from 'vue'
import { auth } from '@/api/auth'
import { showToast } from '@/components/ToastMessage'

export function useChangePassword() {
  const currentPassword = ref('')
  const newPassword = ref('')
  const confirmPassword = ref('')
  const showCurrentPassword = ref(false)
  const showNewPassword = ref(false)
  const showConfirmPassword = ref(false)
  const loading = ref(false)

  // 密码格式验证
  const validatePassword = (password) => {
    const passwordRegex = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)[a-zA-Z\d]{8,20}$/
    return passwordRegex.test(password)
  }

  // 重置表单
  const resetForm = () => {
    currentPassword.value = ''
    newPassword.value = ''
    confirmPassword.value = ''
    showCurrentPassword.value = false
    showNewPassword.value = false
    showConfirmPassword.value = false
  }

  // 修改密码
  const changePassword = async () => {
    // 1. 检查当前密码是否为空
    if (!currentPassword.value) {
      showToast('请输入当前密码', 'warning')
      return false
    }

    // 2. 检查新密码格式
    if (!validatePassword(newPassword.value)) {
      showToast('新密码必须包含大小写字母和数字，长度在8-20位之间', 'warning')
      return false
    }

    // 3. 检查两次密码是否一致
    if (newPassword.value !== confirmPassword.value) {
      showToast('两次输入的密码不一致', 'error')
      return false
    }

    // 4. 检查新密码是否与当前密码相同
    if (newPassword.value === currentPassword.value) {
      showToast('新密码不能与当前密码相同', 'warning')
      return false
    }

    loading.value = true
    try {
      const response = await auth.updatePassword({
        old_password: currentPassword.value,
        new_password: newPassword.value,
        confirm_password: confirmPassword.value
      })

      if (response.data?.code === 200) {
        showToast('密码修改成功', 'success')
        resetForm()
        return true
      } else {
        throw new Error(response.data?.message || '修改密码失败')
      }
    } catch (error) {
      const errorMessage = error.response?.data?.message || '修改密码失败，请重试'
      showToast(errorMessage, 'error')

      // 根据错误类型清空相应输入框
      if (errorMessage.includes('当前密码错误')) {
        currentPassword.value = ''
      }
      if (errorMessage.includes('密码必须') || errorMessage.includes('新密码不能')) {
        newPassword.value = ''
        confirmPassword.value = ''
      }
      return false
    } finally {
      loading.value = false
    }
  }

  return {
    currentPassword,
    newPassword,
    confirmPassword,
    showCurrentPassword,
    showNewPassword,
    showConfirmPassword,
    loading,
    changePassword,
    resetForm
  }
}
